import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() instead of next() to read the entire line

        int maxLength = 10; // Maximum length for the buffer
        char[] buffer = new char[maxLength];

        int length = Math.min(name.length(), maxLength); // Limit input to maximum buffer size
        name.getChars(0, length, buffer, 0); // Copy characters from input to buffer

        System.out.println("Welcome, " + new String(buffer, 0, length)); // Use proper constructor for String conversion
    }
}

